from elasticsearch import Elasticsearch, NotFoundError
import json

class ElasticsearchScriptClient:
    def __init__(self, host: str = "localhost", port: int = 9200, scheme: str = "http"):
        self.es = Elasticsearch(f"{scheme}://{host}:{port}")
        self._check_connection()

    def _check_connection(self):
        if not self.es.ping():
            raise ConnectionError("Could not connect to Elasticsearch! Ensure it's running.")

    def setup_index_and_data(self, index_name: str, docs: list):
        if self.es.indices.exists(index=index_name):
            self.es.indices.delete(index=index_name)
        self.es.indices.create(index=index_name)

        for doc in docs:
            self.es.index(index=index_name, id=doc.get('id'), document=doc)
        self.es.indices.refresh(index=index_name)

    def execute_script_aggregation(self, index_name: str, script_code: str, script_params: dict = None):
        if script_params is None:
            script_params = {}

        search_body = {
            "size": 0,
            "aggs": {
                "dynamic_script_agg_result": {
                    "sum": {
                        "script": {
                            "source": script_code,
                            "lang": "painless",
                            "params": script_params
                        }
                    }
                }
            }
        }
        response = self.es.search(index=index_name, body=search_body)
        return response.get('aggregations', {})

